LARGE_WC2026_BANK = _bank()


def seed_large_wc2026_bank(db: Session, actor: User, league_id: int, round_type: str | None = None) -> dict[str, Any]:
    """Create an approved 5-full-quiz pack, optionally for one round type.

    ``round_type`` uses the planner round key (for example ``millionaire`` or
    ``countdown``), not an internal question type. The operation is idempotent
    per league and commits atomically.
    """
    require_quiz_editor(db, actor, league_id)
    requested = (round_type or "").strip().lower() or None
    if requested and requested not in TYPE_TO_ROUND:
        raise ValueError("Неизвестный формат для загрузки банка")
    qtype = TYPE_TO_ROUND.get(requested) if requested else None
    selected = [row for row in LARGE_WC2026_BANK if not qtype or row["question_type"] == qtype]
    if not selected:
        raise ValueError("Для выбранного формата пакет вопросов не найден")
    existing_rows = db.query(LeagueQuizQuestion).filter(
        LeagueQuizQuestion.league_id == league_id,
        LeagueQuizQuestion.tags.like(f"{SEED_PREFIX}:%"),
    ).all()
    existing_markers = set()
    for row in existing_rows:
        for tag in str(row.tags or "").split(","):
            tag = tag.strip()
            if tag.startswith(f"{SEED_PREFIX}:"):
                existing_markers.add(tag)
    created: list[LeagueQuizQuestion] = []
    try:
        for item in selected:
            marker = _seed_marker(item["seed_key"])
            if marker in existing_markers:
                continue
            payload = {k: v for k, v in item.items() if k not in {"seed_key", "pack"}}
            payload["tags"] = ", ".join([marker, *list(item.get("tags") or [])])
            row = LeagueQuizQuestion(
                league_id=league_id,
                created_by_user_id=actor.id,
                approved_by_user_id=actor.id,
                question_type="choice_4",
                status="draft",
                question_text="Черновик",
                default_points=100,
                question_payload={},
                topics=[],
                repeat_after_days=180,
            )
            db.add(row)
            db.flush()
            _write_question_content(db, row, payload)
            # Validation reads relationship-backed options/sources; flush first so
            # it sees the newly written rows rather than the draft placeholders.
            db.flush()
            db.expire(row, ["options", "aliases", "sources"])
            validate_question_before_approval(row)
            row.status = QUESTION_STATUS_APPROVED
            row.approved_at = utcnow()
            row.approved_by_user_id = actor.id
            db.flush()
            _audit(
                db, question=row, actor=actor, action_type="seeded_wc2026_large_bank",
                after=_question_snapshot(row),
                note=f"Большой банк v3.4.3: полный квиз {item['pack']}, формат {item['question_type']}",
            )
            created.append(row)
        db.commit()
    except Exception:
        db.rollback()
        raise
    for row in created:
        db.refresh(row)
    return {
        "created_count": len(created),
        "existing_count": len(selected) - len(created),
        "available_count": len(selected),
        "total_count": len(selected),
        "round_type": requested,
        "questions": created,
    }
